// src/History.jsx
import React from "react";
import { useNavigate } from "react-router-dom";

const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function History({ employee }) {
  const navigate = useNavigate();

  if (!employee) {
    return (
      <div style={centerScreen}>
        <div>Employee data not found. Please login again.</div>
      </div>
    );
  }

  return (
    <div
      style={{
        minHeight: "100vh",
        background: lightGreen,
        padding: 20,
        fontFamily: "Segoe UI",
      }}
    >
      <div style={card}>
        {/* Header */}
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <button onClick={() => navigate("/profile")} style={backBtn}>
            ⬅ Back
          </button>
          <h2 style={{ color: green, margin: 0 }}>History</h2>
        </div>

        <p style={{ fontSize: 13, color: "#555", marginTop: 6 }}>
          Employee: {employee.name} • {employee.empld}
        </p>

        {/* ======== 3 Cards ======== */}
        <div style={cardContainer}>
          {/* TRAVEL CARD */}
          <div
            style={historyCard}
            onClick={() => navigate("/travel-history")}
          >
            <div style={cardLeft}>
              <h3 style={cardTitle}>Travel Expense History</h3>
              <p style={cardDesc}>View, filter, edit & delete travel records</p>
            </div>
            <div style={cardRight}>›</div>
          </div>

          {/* TICKET CARD */}
          <div
            style={historyCard}
            onClick={() => navigate("/ticket-history")}
          >
            <div style={cardLeft}>
              <h3 style={cardTitle}>Ticket Expense History</h3>
              <p style={cardDesc}>View & manage ticket expense records</p>
            </div>
            <div style={cardRight}>›</div>
          </div>

          {/* BILLS CARD */}
          <div
            style={historyCard}
            onClick={() => navigate("/bills-history")}
          >
            <div style={cardLeft}>
              <h3 style={cardTitle}>Bills Upload History</h3>
              <p style={cardDesc}>View uploaded bills & receipts</p>
            </div>
            <div style={cardRight}>›</div>
          </div>
        </div>
      </div>
    </div>
  );
}

// ---------------- Styles ----------------

const centerScreen = {
  minHeight: "100vh",
  background: lightGreen,
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  fontFamily: "Segoe UI",
};

const card = {
  maxWidth: 900,
  margin: "0 auto",
  background: "#ffffff",
  borderRadius: 16,
  padding: 20,
  boxShadow: "0 6px 20px rgba(0,0,0,0.12)",
};

const backBtn = {
  background: "transparent",
  border: "none",
  color: green,
  fontSize: 16,
  cursor: "pointer",
};

const cardContainer = {
  marginTop: 20,
  display: "flex",
  flexDirection: "column",
  gap: 18,
};

const historyCard = {
  background: "#fff",
  border: "1px solid #eaf8f0",
  borderRadius: 14,
  padding: 18,
  display: "flex",
  justifyContent: "space-between",
  alignItems: "center",
  cursor: "pointer",
  transition: "0.2s",
  boxShadow: "0 2px 10px rgba(0,0,0,0.05)",
};

const cardLeft = {};

const cardTitle = {
  margin: 0,
  color: green,
  fontSize: 18,
};

const cardDesc = {
  margin: "4px 0 0 0",
  fontSize: 13,
  color: "#666",
};

const cardRight = {
  fontSize: 30,
  color: green,
  fontWeight: "bold",
};
